import { auth } from "@clerk/nextjs/server";
import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { generateCode } from "@/lib/utils";
import { z } from "zod";

// GET codes generated by this coach, OR all codes if Super Admin
export async function GET(req: Request) {
    const { userId } = await auth();
    if (!userId) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    const user = await prisma.user.findUnique({ where: { clerkId: userId } });
    if (!user || !["COACH", "SUPER_ADMIN"].includes(user.role)) {
        return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    const url = new URL(req.url);
    const filter = url.searchParams.get("filter") || "ALL";

    let where: any = {};
    if (user.role !== "SUPER_ADMIN") {
        where.generatedBy = user.id;
    }

    if (filter === "USED") {
        where.usedById = { not: null };
    } else if (filter === "UNUSED") {
        where.usedById = null;
        where.isActive = true;
    } else if (filter === "INACTIVE") {
        where.isActive = false;
    }

    const codes = await prisma.accessCode.findMany({
        where,
        include: {
            plan: { select: { name: true } },
            usedBy: { select: { id: true, name: true, email: true } },
        },
        orderBy: { createdAt: "desc" },
    });

    return NextResponse.json(codes.map(c => ({
        ...c,
        planName: c.plan?.name ?? null,
        usedBy: c.usedBy?.name ?? null,
        usedById: c.usedBy?.id ?? null,
        upgradesTo: c.upgradesTo,
    })));
}

// DELETE a code (Super Admin only)
export async function DELETE(req: Request) {
    const { userId } = await auth();
    if (!userId) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    const user = await prisma.user.findUnique({ where: { clerkId: userId } });
    if (!user || user.role !== "SUPER_ADMIN") {
        return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    const { id } = await req.json();
    if (!id) return NextResponse.json({ error: "ID required" }, { status: 400 });

    await prisma.accessCode.delete({ where: { id } });
    return NextResponse.json({ success: true });
}

const codeSchema = z.object({
    planId: z.string().nullable().optional(),
    upgradesTo: z.enum(["PREMIUM", "COACH"]).default("PREMIUM"),
    expiresInHours: z.number().int().positive().optional(),
});

// POST generate a new access code
export async function POST(req: Request) {
    const { userId } = await auth();
    if (!userId) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    const user = await prisma.user.findUnique({ where: { clerkId: userId } });
    if (!user || !["COACH", "SUPER_ADMIN"].includes(user.role)) {
        return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    const body = await req.json();
    const parsed = codeSchema.safeParse(body);
    if (!parsed.success) return NextResponse.json({ error: parsed.error.flatten() }, { status: 400 });

    const upgradesTo = parsed.data.upgradesTo as "PREMIUM" | "COACH";

    if (upgradesTo === "COACH" && user.role !== "SUPER_ADMIN") {
        return NextResponse.json({ error: "Only admins can generate coach codes" }, { status: 403 });
    }

    let expiresAt: Date | null = null;
    if (parsed.data.expiresInHours) {
        expiresAt = new Date();
        expiresAt.setHours(expiresAt.getHours() + parsed.data.expiresInHours);
    }

    const code = await prisma.accessCode.create({
        data: {
            code: generateCode(8),
            planId: parsed.data.planId ?? null,
            generatedBy: user.id,
            upgradesTo,
            expiresAt,
        },
    });

    return NextResponse.json(code, { status: 201 });
}
